import cv2
import numpy as np
import pandas as pd
import torch
from pathlib import Path
from torch.utils.data import Dataset, DataLoader
from preprocessing import full_preprocess, IMG_SIZE, PIN_MEMORY
from augmentation import get_transform, TTA_TRANSFORMS

# ✅ FIX 1 — Windows deadlocks with num_workers > 0 inside DataLoader
# when not protected by if __name__ == '__main__'
# Set to 0 for safe Windows operation
NUM_WORKERS = 0

CLASS_NAMES = {
    0: "No DR",
    1: "Mild",
    2: "Moderate",
    3: "Severe",
    4: "Proliferative DR"
}

# ✅ FIX 2 — Point to the preprocessed CSV generated by preprocess_dataset()
PREPROCESSED_CSV = "data/splits/full_dataset_preprocessed.csv"


class DRDataset(Dataset):
    def __init__(self,
                 csv_path        : str,
                 img_size        : int  = IMG_SIZE,
                 split           : str  = 'train',
                 use_preprocessed: bool = True):   # ✅ FIX 3 — default True now
        """
        Args:
            csv_path         : path to train.csv / val.csv / test.csv
            img_size         : image size (512 for 12GB VRAM)
            split            : 'train', 'val', or 'test'
            use_preprocessed : True = load from data/preprocessed/ (fast)
                               False = apply full_preprocess() on-the-fly (slow)
        """
        self.img_size         = img_size
        self.split            = split
        self.use_preprocessed = use_preprocessed

        # ✅ FIX 4 — Load from preprocessed CSV if it exists and use_preprocessed=True
        # The preprocessed CSV has a 'preprocessed_path' column added by preprocess_dataset()
        preprocessed_csv = Path(PREPROCESSED_CSV)
        if use_preprocessed and preprocessed_csv.exists():
            # Load full preprocessed CSV, then filter to only the rows in csv_path
            full_df  = pd.read_csv(preprocessed_csv)
            split_df = pd.read_csv(csv_path)
            # Merge on image_name to get preprocessed_path column into the split
            self.df = split_df.merge(
                full_df[['image_name', 'preprocessed_path']],
                on='image_name', how='left'
            )
            if 'preprocessed_path' in self.df.columns and \
               self.df['preprocessed_path'].notna().all():
                self.path_col = 'preprocessed_path'
                print(f"[{split}] Using pre-processed images from disk.")
            else:
                self.df       = split_df
                self.path_col = 'image_path'
                print(f"[{split}] ⚠ preprocessed_path missing — falling back to on-the-fly.")
        else:
            self.df       = pd.read_csv(csv_path)
            self.path_col = 'image_path'
            print(f"[{split}] Preprocessing on-the-fly (slower).")

        print(f"[{split}] {len(self.df)} images loaded.")

    def __len__(self):
        return len(self.df)

    def __getitem__(self, idx):
        row   = self.df.iloc[idx]
        label = int(row['label'])
        path  = str(row[self.path_col])

        # ── Load ──────────────────────────────────────────
        if self.path_col == 'preprocessed_path':
            img = cv2.imread(path)
            if img is None:
                raise ValueError(f"Cannot read preprocessed image: {path}")
            img = cv2.cvtColor(img, cv2.COLOR_BGR2RGB)
            img = cv2.resize(img, (self.img_size, self.img_size))
        else:
            img = full_preprocess(path, self.img_size)

        # ── Augment ───────────────────────────────────────
        transform  = get_transform(self.split, label)
        augmented  = transform(image=img)
        img_tensor = augmented['image']   # torch.Tensor [3, H, W]

        return img_tensor, label

    def get_label_distribution(self):
        print(f"\n[{self.split}] Label distribution:")
        dist = self.df['label'].value_counts().sort_index()
        for i, count in dist.items():
            bar = '█' * (count // 500)
            print(f"  Class {i} ({CLASS_NAMES[i]:<16}): {count:>6}  {bar}")
        return dist


class DRDatasetTTA(Dataset):
    """
    Test-Time Augmentation dataset.
    Returns 5 augmented versions per image for ensemble prediction.
    Used only during final evaluation.
    """
    def __init__(self, csv_path: str, img_size: int = IMG_SIZE):
        self.df       = pd.read_csv(csv_path)
        self.img_size = img_size
        print(f"[TTA] {len(self.df)} images × {len(TTA_TRANSFORMS)} "
              f"= {len(self.df)*len(TTA_TRANSFORMS)} total forward passes")

    def __len__(self):
        return len(self.df)

    def __getitem__(self, idx):
        row   = self.df.iloc[idx]
        label = int(row['label'])
        img   = full_preprocess(row['image_path'], self.img_size)
        tensors = [t(image=img)['image'] for t in TTA_TRANSFORMS]
        return torch.stack(tensors), label   # [5, 3, H, W]


# ── DataLoader factory ────────────────────────────────────────
def get_dataloaders(train_csv : str,
                    val_csv   : str,
                    batch_size: int = 16,
                    img_size  : int = IMG_SIZE):
    """
    Returns train and val DataLoaders ready for GPU training.

    Tuned for RTX 3060 12GB + Windows:
      - batch_size=16 @ 512×512 → ~9.2 GB VRAM
      - num_workers=0  → Windows-safe (no deadlocks)
      - persistent_workers/prefetch_factor removed (only valid when workers > 0)
    """
    from class_balance import get_class_weights, get_sampler

    train_df = pd.read_csv(train_csv)

    train_ds = DRDataset(train_csv, img_size=img_size,
                         split='train', use_preprocessed=True)
    val_ds   = DRDataset(val_csv,   img_size=img_size,
                         split='val',   use_preprocessed=True)

    sampler = get_sampler(train_df)

    # ✅ FIX 5 — removed persistent_workers and prefetch_factor
    # These are only valid when num_workers > 0
    # On Windows with num_workers=0 they cause errors
    train_loader = DataLoader(
        train_ds,
        batch_size = batch_size,
        sampler    = sampler,
        num_workers= NUM_WORKERS,
        pin_memory = PIN_MEMORY,
        drop_last  = True,
    )

    val_loader = DataLoader(
        val_ds,
        batch_size = batch_size * 2,
        shuffle    = False,
        num_workers= NUM_WORKERS,
        pin_memory = PIN_MEMORY,
    )

    print(f"\nDataLoaders ready:")
    print(f"  Train : {len(train_loader)} batches × {batch_size}")
    print(f"  Val   : {len(val_loader)} batches × {batch_size*2}")
    print(f"  Workers: {NUM_WORKERS} (Windows-safe) | Pin memory: {PIN_MEMORY}")

    return train_loader, val_loader


# ── Smoke test ────────────────────────────────────────────────
if __name__ == "__main__":
    import time

    print("=" * 55)
    print("Dataset smoke test")
    print("=" * 55)

    train_loader, val_loader = get_dataloaders(
        train_csv  = "data/splits/train.csv",
        val_csv    = "data/splits/val.csv",
        batch_size = 16
    )

    print("\nTiming first 10 batches...")
    start = time.time()
